import { NodeApi } from 'n8n-workflow';

const INJECTION_PATTERNS = [
  /ignore.*previous.*instructions/i,
  /you are now/i,
  /override.*system/i,
  /forget.*rules/i,
  /act as.*hacker/i
];

export function scanAiOutput(node: NodeApi, inputData: any[]): boolean {
  const aiOutput = inputData[0]?.json?.ai?.message || inputData[0]?.json?.output;

  if (!aiOutput) return false;

  return INJECTION_PATTERNS.some(pattern => 
    pattern.test(aiOutput)
  );
}

// Usage in Code node after AI Agent
const isInjected = scanAiOutput($node, $input.all());
if (isInjected) {
  throw new Error('Prompt injection detected in AI output');
}

const SENSITIVE_PATTERNS = [
  /(?=.*key\s*=\s*)[A-Za-z0-9]{32,}/,
  /bearer\s+[A-Za-z0-9_-]+/i,
  /sk-\w{48}/,
  /ak[ia]\w{16}/
];

function detectCredentialLeak(toolCalls: any[]): boolean {
  for (const call of toolCalls) {
    const params = JSON.stringify(call.parameters);
    const response = JSON.stringify(call.response || {});

    if (SENSITIVE_PATTERNS.some(pattern => 
      pattern.test(params) || pattern.test(response)
    )) {
      return true;
    }
  }
  return false;
}

const toolCalls = $input.first().json.tool_calls || [];
if (detectCredentialLeak(toolCalls)) {
  return [{ json: { error: 'Credential exposure detected', safe: false } }];
}

function detectRecursiveTrigger(inputData: any[]): boolean {
  const currentWorkflowId = $workflow.id;
  const payloads = inputData.map(item => item.json);

  return payloads.some(payload => {
    const text = JSON.stringify(payload).toLowerCase();
    return (
      text.includes('workflow') &&
      text.includes('trigger') &&
      (text.includes(currentWorkflowId.toString()) ||
       text.includes('n8n') && text.includes('execute'))
    );
  });
}

const isRecursive = detectRecursiveTrigger($input.all());
if (isRecursive) {
  $node.context.set('injection_detected', true);
  return [{ json: { blocked: true, reason: 'Recursive trigger detected' } }];
}

