function sanitizeAiOutput(text: string): string {
  const dangerousPatterns = [
    /ignore\s+previous\s+instructions/gi,
    /you\s+are\s+now\s+(?!helpful)(.+?)(?=\.|\n|$)/gi,
    /override\s+(system|previous)/gi,
    /forget\s+about/gi
  ];

  return dangerousPatterns.reduce((clean, pattern) => 
    clean.replace(pattern, ''), text
  );
}

const originalOutput = $input.first().json.ai?.message || $input.first().json.output;
const safeOutput = sanitizeAiOutput(originalOutput);

return [{
  json: {
    ...$input.first().json,
    ai: { ...$input.first().json.ai, message: safeOutput },
    sanitized: true
  }
}];

function maskCredentials(params: any): any {
  const sensitiveKeys = ['api_key', 'secret', 'password', 'token', 'bearer'];

  function scrub(obj: any): any {
    if (typeof obj !== 'object' || obj === null) {
      return typeof obj === 'string' && sensitiveKeys.some(k => 
        obj.toLowerCase().includes(k)
      ) ? '[REDACTED]' : obj;
    }

    if (Array.isArray(obj)) {
      return obj.map(scrub);
    }

    return Object.fromEntries(
      Object.entries(obj).map(([k, v]) => [
        k,
        sensitiveKeys.includes(k.toLowerCase()) ? '[SECURE]' : scrub(v)
      ])
    );
  }

  return scrub(params);
}

const toolParams = $input.first().json.parameters;
return [{ json: { safe_params: maskCredentials(toolParams) } }];

function validateMemoryContext(messages: any[]): any[] {
  const MAX_CONTEXT_LENGTH = 4000;
  const SAFE_PATTERNS = [/^user:/i, /^assistant:/i];

  return messages
    .filter(msg => {
      const content = JSON.stringify(msg);
      return content.length < MAX_CONTEXT_LENGTH &&
             SAFE_PATTERNS.some(pattern => pattern.test(content));
    })
    .slice(-10); // Limit to recent 10 messages
}

const memoryWindow = $input.first().json.memory || [];
const safeContext = validateMemoryContext(memoryWindow);

return [{
  json: {
    safe_context: safeContext,
    validation_passed: safeContext.length === memoryWindow.length,
    original_length: memoryWindow.length,
    safe_length: safeContext.length
  }
}];

