import { Vex } from '@vex_dev/sdk';

// n8n Code node after AI Agent
const vex = new Vex({
  token: $secrets.VEX_TOKEN,
  framework: 'n8n',
  workflowId: $workflow.id.toString(),
  nodeId: $node.name
});

const aiOutput = $input.first().json;
const result = await vex.scan({
  type: 'prompt_injection',
  payload: aiOutput,
  context: {
    workflow_name: $workflow.name,
    ai_model: aiOutput.model || 'unknown',
    tool_calls: aiOutput.tool_calls?.length || 0
  }
});

if (result.threats.length > 0) {
  // Auto-block and log
  await vex.block({
    threat_id: result.threats[0].id,
    severity: result.threats[0].severity,
    remediation: 'sanitize_output'
  });

  return [{
    json: {
      blocked: true,
      threats: result.threats,
      vex_remediation: result.autoFix
    }
  }];
}

// Safe output with Vex metadata
return [{
  json: {
    ...aiOutput,
    vex_verified: true,
    scan_id: result.scanId
  }
}];
